class Solution(object):
    def generateString(self, str1, str2):
        """
        :type str1: str
        :type str2: str
        :rtype: str
        """
        n = len(str1)
        m = len(str2)
        result_len = n + m - 1

        # DP: dp[i][j] = whether we can reach position i with match length j of str2
        # match length j means suffix of result[0..i] has j characters matching str2[0..j-1]

        # Try to build result greedily
        result = [None] * result_len

        # Fill fixed positions first
        for i in range(n):
            if str1[i] == 'T':
                for j in range(m):
                    if result[i + j] is None:
                        result[i + j] = str2[j]
                    elif result[i + j] != str2[j]:
                        return ""  # Conflict

        # Build KMP next table for str2
        next_arr = [0] * m
        for i in range(1, m):
            j = next_arr[i - 1]
            while j > 0 and str2[i] != str2[j]:
                j = next_arr[j - 1]
            if str2[i] == str2[j]:
                j += 1
            next_arr[i] = j

        # Try to fill unknowns greedily with 'a'
        for i in range(result_len):
            if result[i] is None:
                # Try 'a' first
                for ch in ['a', 'b']:
                    result[i] = ch
                    # Check if valid so far
                    valid = True

                    # Check all str1 constraints up to position i
                    for start in range(max(0, i - m + 1), min(n, i + 1)):
                        if start + m - 1 <= i:
                            substr = ''.join(result[start:start+m])
                            if str1[start] == 'T' and substr != str2:
                                valid = False
                                break
                            if str1[start] == 'F' and substr == str2:
                                valid = False
                                break

                    if valid:
                        break
                else:
                    return ""

        # Verify solution
        result_str = ''.join(result)
        for i in range(n):
            substr = result_str[i:i+m]
            if str1[i] == 'T' and substr != str2:
                return ""
            if str1[i] == 'F' and substr == str2:
                return ""

        return result_str
